void MRFCircumVentCmd::SetSelectorListBasedOnPathElementAgent(CATUnicodeString geomSetType, CATPathElement* &pPathElement, CATDlgSelectorList* &pOnSelectorList, CATBaseUnknown_var & spOnVariableToStore)
{
	if (NULL != pPathElement && pOnSelectorList)
	{
		CATUnicodeString surfaceAliasName;

			if (NULL != _pHSO && 0 == _pHSO->IsMember(pPathElement))
			{
				_pHSO->Empty();
				_pHSO->AddElement(pPathElement);
			}

			CATBaseUnknown* pSelectedObject = pPathElement->CurrentElement(); // No need to release the returned object

			bool isErrorThrown = false;
			if (pSelectedObject)
			{
				CATIAlias_var pAliasON3DCurve(pSelectedObject);
				if (!!pAliasON3DCurve) {
					surfaceAliasName = pAliasON3DCurve->GetAlias();
				}

				isErrorThrown = ThrowErrow(surfaceAliasName, geomSetType);

				if (!isErrorThrown)
				{
					CATBoolean isSameCurve = CATFalse;
					if (spOnVariableToStore == NULL_var)
						spOnVariableToStore = pSelectedObject;
					else if (spOnVariableToStore != NULL_var && !spOnVariableToStore->IsEqual(pSelectedObject))
					{
						spOnVariableToStore->Release();
						spOnVariableToStore = NULL;
						spOnVariableToStore = pSelectedObject;
					}
					else
						isSameCurve = CATTrue;

					_pMRFCircumVentDlg->SetSelectorListVentGeomSet(surfaceAliasName, pOnSelectorList);

				}
				else
				{
					if (spOnVariableToStore != NULL_var)
						spOnVariableToStore->Release();	spOnVariableToStore = NULL;

					_pMRFCircumVentDlg->SetSelectorListVentGeomSet("No Selection", pOnSelectorList);
					if (_pHSO)
						_pHSO->RemoveElement(pPathElement);

					pPathElement = NULL;

				}
			}
	}

	if (!!spOnVariableToStore && !_spGSDFactory)
	{
		CATIMmiMechanicalFeature_var spSurfaceFeature = spOnVariableToStore;
		if (NULL_var == _spGSDFactory && NULL_var != spSurfaceFeature)
		{
			HRESULT rc;
			CATIMmiPrtContainer_var spPrtCont;
			rc = spSurfaceFeature->GetPrtContainer(spPrtCont);
			if (NULL_var != spPrtCont)
			{
				rc = spPrtCont->QueryInterface(IID_MRFIGSDFactory, (void**)& _spGSDFactory);
			}
		}
	}
}

void MRFCircumVentCmd::ReadSelectedGeomSet(CATUnicodeString geomSetType, CATBaseUnknown_var spOnGeomSet)
{
	HRESULT hr = E_FAIL;

	CATApplicationFrame * pAppFrame = CATApplicationFrame::GetFrame();
	if (NULL == pAppFrame)
		return;

	CATDlgWindow * pMainWindow = pAppFrame->GetMainWindow();
	if (NULL == pMainWindow)
		return;


	CATListValCATBaseUnknown_var ListResults, listOfCircumGeomSet;

	CATIBodyRequest * pCurBody = NULL;
	if (spOnGeomSet != NULL_var)
	{
		CATIGSMTool_var spGSMToolOnSelGeomSet = spOnGeomSet;
		int isOrderedGeoSet;
		if (!!spGSMToolOnSelGeomSet)
			spGSMToolOnSelGeomSet->GetType(isOrderedGeoSet);

		if (isOrderedGeoSet)
		{
			hr = spOnGeomSet->QueryInterface(IID_CATIBodyRequest, (void**)&pCurBody);
			if (SUCCEEDED(hr) && NULL != pCurBody)
			{

				pCurBody->GetDirectBodies(ListResults);
				if (ListResults.Size() > 0)
				{
					for (int j = 1; j <= ListResults.Size(); j++)
					{
						CATBaseUnknown_var pCurBodyOnCircumGeomSet = ListResults[j];
						CATUnicodeString strAlias;
						CATIAlias_var spAlias = pCurBodyOnCircumGeomSet;
						if (!!spAlias && !!pCurBodyOnCircumGeomSet)
						{
							CATIBodyRequest_var spBodyReqOnCircumVent = pCurBodyOnCircumGeomSet;
							if (!!spBodyReqOnCircumVent)
								listOfCircumGeomSet.Append(pCurBodyOnCircumGeomSet);
							strAlias = spAlias->GetAlias();

						}


					}
				}
				else if (!_spMRFCircumVentFeat)
				{
						CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
						if (NULL == pErrPanel)
							return;

						// Set the text
						CATUnicodeString usWndTitle = "Warning Message", usMessage;

						usMessage.Append("No features under selected Geometrical Set.\n");
						//usMessage.Append("The Product with Name: \"" + strOnNameOfPrdToInstantiate + "\" and Rev: \" " + strOnRev + "does not exists in database.\n");


						pErrPanel->DisplayBlocked(usMessage, usWndTitle);

						pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;

				}
				pCurBody->Release(); pCurBody = NULL;
			}
		}
		else
		{


			CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
			if (NULL == pErrPanel)
				return;

			// Set the text
			CATUnicodeString usWndTitle = "Warning Message", usMessage;

			usMessage.Append("Select Correct Ordered Geometrical Set\n");
			//usMessage.Append("The Product with Name: \"" + strOnNameOfPrdToInstantiate + "\" and Rev: \" " + strOnRev + "does not exists in database.\n");


			pErrPanel->DisplayBlocked(usMessage, usWndTitle);

			pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;
		}


	}

	if (listOfCircumGeomSet.Size() > 0)
	{
		if(geomSetType.Compare("DefaultRevolves"))
			this->CollectRevolveFromRegularVentInStrcut(listOfCircumGeomSet);
		else if(geomSetType.Compare("MergedRevolves"))
			this->CollectRevolveFromMergedVentInStrcut(listOfCircumGeomSet);
	else if(geomSetType.Compare("LateralRevolves"))
			this->CollectRevolveFromLateralVentInStrcut(listOfCircumGeomSet);
	}
}


void MRFCircumVentCmd::CollectRevolveFromRegularVentInStrcut(CATListValCATBaseUnknown_var spListOnCircumVentSet)
{
	_listOfRegularVentInfoStruct.RemoveAll();

	for (int i = 1; i <= spListOnCircumVentSet.Size(); i++)
	{
		CATListValCATBaseUnknown_var *spListOnFeaturesUnderCircumVentSet = NULL;
		CATIBodyRequest_var pCurBody = spListOnCircumVentSet[i];
		if (pCurBody != NULL_var)
		{
			_pRegularVentInfo = new RegularVentInfo();

			_pRegularVentInfo->spRegVentProfParentGeomSet = pCurBody;

			CATINavigateObject_var spNavigObject;
			spNavigObject = pCurBody;
			if (!!spNavigObject)
				spListOnFeaturesUnderCircumVentSet = spNavigObject->GetChildren();
			if (!spListOnFeaturesUnderCircumVentSet)
				continue;

			if (spListOnFeaturesUnderCircumVentSet->Size() > 0)
			{
				for (int j = 1; j <= spListOnFeaturesUnderCircumVentSet->Size(); j++)
				{
					CATBaseUnknown_var pCurBodyOnFeatures = (*spListOnFeaturesUnderCircumVentSet)[j];
					CATUnicodeString strAlias;
					CATIAlias_var spAlias = pCurBodyOnFeatures;
					if (!!spAlias && !!pCurBodyOnFeatures)
					{
						strAlias = spAlias->GetAlias();
						
						CATIGSMUseRevol_var spGSMUseRevol = pCurBodyOnFeatures;

						if (!!spGSMUseRevol)
						{
							_pRegularVentInfo->spRegVentProf_Revol = spGSMUseRevol;

							break;
						}
						


					}


				}

				_listOfRegularVentInfoStruct.Append(_pRegularVentInfo);
			}
			pCurBody->Release(); pCurBody = NULL;
		}
	}

	CATDlgMultiList* pMultiListLateral = _pMRFCircumVentDlg->GetMultiList();
	if (pMultiListLateral)
	{
		CATUnicodeString temp;
		temp.BuildFromNum(_listOfRegularVentInfoStruct.Size());
		pMultiListLateral->SetColumnItem(1, temp, 6, CATDlgDataModify);

	}

}

CATBoolean MRFCircumVentCmd::CheckIfShowMode(const CATIVisProperties_var & spVisu, const CATBaseUnknown_var ispSpecToCheck)
{
	CATBoolean bRetVal = CATFalse;

	if (NULL_var == spVisu)
		return bRetVal;

	CATVisPropertiesValues pPropVal;
	HRESULT hr = spVisu->GetPropertiesAtt(pPropVal, CATVPShow, CATVPGlobalType);
	if (FAILED(hr))
		return bRetVal;

	CATShowAttribut enumShowNoShow;
	pPropVal.GetShowAttr(enumShowNoShow);

	// If the part is hidden then return
	if (CATNoShowAttr == enumShowNoShow)
	{
		return bRetVal;
	}

	// Spec is not available to check
	if (CATShowAttr == enumShowNoShow && NULL_var == ispSpecToCheck)
	{
		return CATTrue;
	}
	else if (CATShowAttr == enumShowNoShow && NULL_var != ispSpecToCheck)
	{
		//pPropVal.SetShow(CATNoShowAttr);
		//spVisu->SetPropertiesAtt(pPropVal, CATVPShow);
		return CATTrue;
	}

	return bRetVal;
}

bool MRFCircumVentCmd::ThrowErrow(CATUnicodeString selGeomSetName, CATUnicodeString typeOfGeomSet)
{
	bool errorFound = false;

	CATApplicationFrame * pAppFrame = CATApplicationFrame::GetFrame();
		if (NULL == pAppFrame)
			return errorFound;

		CATDlgWindow * pMainWindow = pAppFrame->GetMainWindow();
		if (NULL == pMainWindow)
			return errorFound;

		CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
		if (NULL == pErrPanel)
			return errorFound;

		// Set the text
		CATUnicodeString usWndTitle = "Warning Message", usMessage;

		if (typeOfGeomSet.Compare("DefaultRevolves") && !selGeomSetName.Compare("RegularVentProfiles"))
		{
			usMessage.Append("Selected vent is not a RegularVent\n. Select \"RegularVentProfiles\" ordered geom set\n");
			pErrPanel->DisplayBlocked(usMessage, usWndTitle);
			errorFound = true;

		}
		else if (typeOfGeomSet.Compare("MergedRevolves") && !selGeomSetName.Compare("MergedVentProfiles"))
		{
			usMessage.Append("Selected vent is not a MergedVentSet\n. Select \"MergedVentProfiles\" ordered geom set\n");
			pErrPanel->DisplayBlocked(usMessage, usWndTitle);
			errorFound = true;


		}
		else if (typeOfGeomSet.Compare("LateralRevolves") && !selGeomSetName.Compare("LateralVentProfiles"))
		{
			usMessage.Append("Selected vent is not a LateralVentSet\n. Select \"LateralVentProfiles\" ordered geom set\n");
			pErrPanel->DisplayBlocked(usMessage, usWndTitle);
			errorFound = true;

		}

		pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;

	return errorFound;
}

void MRFCircumVentCmd::CollectRevolveFromMergedVentInStrcut(CATListValCATBaseUnknown_var spListOnMergedVentSet)
{
	_listOfMergedVentInfoStruct.RemoveAll();

	for (int i = 1; i <= spListOnMergedVentSet.Size(); i++)
	{
		CATListValCATBaseUnknown_var *spListOnFeaturesUnderCircumVentSet = NULL;
		CATIBodyRequest_var pCurBody = spListOnMergedVentSet[i];
		if (pCurBody != NULL_var)
		{
			_pMergedVentInfo = new MergedVentInfo();

			_pMergedVentInfo->spMergedVentProfParentGeomSet = pCurBody;

			CATINavigateObject_var spNavigObject;
			spNavigObject = pCurBody;
			if (!!spNavigObject)
				spListOnFeaturesUnderCircumVentSet = spNavigObject->GetChildren();
			if (!spListOnFeaturesUnderCircumVentSet)
				continue;

			if (spListOnFeaturesUnderCircumVentSet->Size() > 0)
			{
				for (int j = 1; j <= spListOnFeaturesUnderCircumVentSet->Size(); j++)
				{
					CATBaseUnknown_var pCurBodyOnFeatures = (*spListOnFeaturesUnderCircumVentSet)[j];
					CATUnicodeString strAlias;
					CATIAlias_var spAlias = pCurBodyOnFeatures;
					if (!!spAlias && !!pCurBodyOnFeatures)
					{
						strAlias = spAlias->GetAlias();

						CATIGSMUseRevol_var spGSMUseRevol = pCurBodyOnFeatures;

						if (!!spGSMUseRevol)
						{
							_pMergedVentInfo->spMergedVentProf_Revol = spGSMUseRevol;

							break;
						}



					}


				}

				_listOfMergedVentInfoStruct.Append(_pMergedVentInfo);
			}
			pCurBody->Release(); pCurBody = NULL;
		}
	}

	CATDlgMultiList* pMultiListLateral = _pMRFCircumVentDlg->GetMultiList();
	if (pMultiListLateral)
	{
		CATUnicodeString temp;
		temp.BuildFromNum(_listOfMergedVentInfoStruct.Size());
		pMultiListLateral->SetColumnItem(2, temp, 6, CATDlgDataModify);
	}

}

void MRFCircumVentCmd::CollectRevolveFromLateralVentInStrcut(CATListValCATBaseUnknown_var spListOnLateralVentSet)
{
	_listOfLateralVentInfoStruct.RemoveAll();

	for (int i = 1; i <= spListOnLateralVentSet.Size(); i++)
	{
		CATListValCATBaseUnknown_var *spListOnFeaturesUnderCircumVentSet = NULL;
		CATIBodyRequest_var pCurBody = spListOnLateralVentSet[i];
		if (pCurBody != NULL_var)
		{
			_pLateralVentInfo = new LateralVentInfo();

			_pLateralVentInfo->spLateralVentListParent = pCurBody;
			
			CATINavigateObject_var spNavigObject;
			spNavigObject = pCurBody;
			if (!!spNavigObject)
				spListOnFeaturesUnderCircumVentSet = spNavigObject->GetChildren();
			if (!spListOnFeaturesUnderCircumVentSet)
				continue;

			if (spListOnFeaturesUnderCircumVentSet->Size() > 0)
			{
				for (int j = 1; j <= spListOnFeaturesUnderCircumVentSet->Size(); j++)
				{
					CATBaseUnknown_var pCurBodyOnFeatures = (*spListOnFeaturesUnderCircumVentSet)[j];
					CATUnicodeString strAlias, objType;
					CATIAlias_var spAlias = pCurBodyOnFeatures;
					if (!!spAlias && !!pCurBodyOnFeatures)
					{
						strAlias = spAlias->GetAlias();

						CATIGSMUseProject_var spGSMUseRevol = pCurBodyOnFeatures;

						if (!!spGSMUseRevol)
						{
							_pLateralVentInfo->spListOfLateralVentProf.Append(spGSMUseRevol);

						}
						else
						{
							CATIBodyRequest_var spOnCircumVentInsideLateral = pCurBodyOnFeatures;

							if (!!spOnCircumVentInsideLateral)
							{
								CATListValCATBaseUnknown_var *spListOnFeaturesUnderCircumVentSetLoc = NULL;

								CATINavigateObject_var spNavigObjectCircumVent;
								spNavigObjectCircumVent = spOnCircumVentInsideLateral;
								if (!!spNavigObjectCircumVent)
									spListOnFeaturesUnderCircumVentSetLoc = spNavigObjectCircumVent->GetChildren();
								if (!spListOnFeaturesUnderCircumVentSetLoc)
									continue;

								if (spListOnFeaturesUnderCircumVentSetLoc->Size() > 0)
								{
									for (int j = 1; j <= spListOnFeaturesUnderCircumVentSetLoc->Size(); j++)
									{
										CATBaseUnknown_var pCurBodyOnFeaturesLoc = (*spListOnFeaturesUnderCircumVentSetLoc)[j];
										CATUnicodeString strAlias, objType;
										CATIAlias_var spAlias = pCurBodyOnFeaturesLoc;
										if (!!spAlias && !!pCurBodyOnFeaturesLoc)
										{
											strAlias = spAlias->GetAlias();
											CATIGSMUseRevol_var spGSMUseRevol = pCurBodyOnFeaturesLoc;

											if (!!spGSMUseRevol && CheckIfShowMode(spGSMUseRevol, spGSMUseRevol))
											{
												_pLateralVentInfo->spRegularRevolve = spGSMUseRevol;
												_pLateralVentInfo->spRegularRevolParent = spOnCircumVentInsideLateral;

												break;
											}
										}
									}
								}
							}

						}
					}
				}

				_listOfLateralVentInfoStruct.Append(_pLateralVentInfo);
			}
			pCurBody->Release(); pCurBody = NULL;
		}
	}

	CATDlgMultiList* pMultiListLateral = _pMRFCircumVentDlg->GetMultiList();
	if (pMultiListLateral)
	{
		CATUnicodeString temp;
		temp.BuildFromNum(_listOfLateralVentInfoStruct.Size());
		pMultiListLateral->SetColumnItem(3, temp,6,CATDlgDataModify);
	}
}

void MRFCircumVentCmd::ReadAndSetCircumVentValuesFromMultiList()
{
	CATDlgMultiList* pSelListOnInputVal = NULL;
	if (_pMRFCircumVentDlg)
		pSelListOnInputVal =  _pMRFCircumVentDlg->GetMultiList();

	if (pSelListOnInputVal)
	{
		int rowCount = 	pSelListOnInputVal->GetLineCount();
		int columnCount = 	pSelListOnInputVal->GetColumnCount();

		if (rowCount > 0)
		{
			while (columnCount >= 2)
			{
				int indexColumn = columnCount - 1;
				
					CATUnicodeString width, depth, firstPadAng, secPadAng, firstFillRad, secFilltRad;
					pSelListOnInputVal->GetColumnItem(indexColumn, width, 0);
					pSelListOnInputVal->GetColumnItem(indexColumn, depth, 1);
					pSelListOnInputVal->GetColumnItem(indexColumn, firstPadAng, 2);
					pSelListOnInputVal->GetColumnItem(indexColumn, secPadAng, 3);
					pSelListOnInputVal->GetColumnItem(indexColumn, firstFillRad, 4);
					pSelListOnInputVal->GetColumnItem(indexColumn, secFilltRad, 5);

					if (columnCount == 4)
					{
						 width.ConvertToNum(&_LateralVentInputValuse.width);
						 depth.ConvertToNum(&_LateralVentInputValuse.depth);
						 firstPadAng.ConvertToNum(&_LateralVentInputValuse.firstPaddingAng);
						 secPadAng.ConvertToNum(&_LateralVentInputValuse.secPaddingAng);
						 firstFillRad.ConvertToNum(&_LateralVentInputValuse.firstFilltRad);
						 secFilltRad.ConvertToNum(&_LateralVentInputValuse.secFilltRad);
				
					}
					else if (columnCount == 3)
					{
						 width.ConvertToNum(&_MergedVentInputValuse.width);
						 depth.ConvertToNum(&_MergedVentInputValuse.depth);
						 firstPadAng.ConvertToNum(&_MergedVentInputValuse.firstPaddingAng);
						 secPadAng.ConvertToNum(&_MergedVentInputValuse.secPaddingAng);
						 firstFillRad.ConvertToNum(&_MergedVentInputValuse.firstFilltRad);
						 secFilltRad.ConvertToNum(&_MergedVentInputValuse.secFilltRad);
				
					}
					else if (columnCount == 2)
					{
						 width.ConvertToNum(&_RegVentInputValuse.width);
						 depth.ConvertToNum(&_RegVentInputValuse.depth);
						 firstPadAng.ConvertToNum(&_RegVentInputValuse.firstPaddingAng);
						 secPadAng.ConvertToNum(&_RegVentInputValuse.secPaddingAng);
						 firstFillRad.ConvertToNum(&_RegVentInputValuse.firstFilltRad);
						 secFilltRad.ConvertToNum(&_RegVentInputValuse.secFilltRad);
				
					}

				--columnCount;
			}
			
		}
	}

}

void MRFCircumVentCmd::ReadDefaultValuesOfMultiListFromNLS()
{
	CATString StringVal;
	CATUnicodeString width, depth, firstPadAng, secPadAng, firstFillRad, secFillRad;

	CATDlgMultiList* pMultiList = _pMRFCircumVentDlg->GetMultiList();

	for (int i = 1; i <= 3; i++)
	{
		if (i == 1)
			StringVal = "MRFCircumVentCmd.DefaultVent";
		else if (i == 2)
			StringVal = "MRFCircumVentCmd.MergedVent";
		else if (i == 3)
			StringVal = "MRFCircumVentCmd.LateralVent";
		
		width = CATMsgCatalog::BuildMessage("MRFCircumVentCmd", StringVal + ".Width");
		depth = CATMsgCatalog::BuildMessage("MRFCircumVentCmd", StringVal + ".Depth");
		firstPadAng = CATMsgCatalog::BuildMessage("MRFCircumVentCmd", StringVal + ".FirstPaddingAngle");
		secPadAng = CATMsgCatalog::BuildMessage("MRFCircumVentCmd", StringVal + ".SecondPaddingAngle");
		firstFillRad = CATMsgCatalog::BuildMessage("MRFCircumVentCmd", StringVal + ".FirstFilletRadius");
		secFillRad = CATMsgCatalog::BuildMessage("MRFCircumVentCmd", StringVal + ".SecondFilletRadius");

		if (i == 1)
		{
			width.ConvertToNum(&_RegVentInputValuse.width);
			depth.ConvertToNum(&_RegVentInputValuse.depth);
			firstPadAng.ConvertToNum(&_RegVentInputValuse.firstPaddingAng);
			secPadAng.ConvertToNum(&_RegVentInputValuse.secPaddingAng);
			firstFillRad.ConvertToNum(&_RegVentInputValuse.firstFilltRad);
			secFillRad.ConvertToNum(&_RegVentInputValuse.secFilltRad);

		}
		else if (i == 2)
		{
			width.ConvertToNum(&_MergedVentInputValuse.width);
			depth.ConvertToNum(&_MergedVentInputValuse.depth);
			firstPadAng.ConvertToNum(&_MergedVentInputValuse.firstPaddingAng);
			secPadAng.ConvertToNum(&_MergedVentInputValuse.secPaddingAng);
			firstFillRad.ConvertToNum(&_MergedVentInputValuse.firstFilltRad);
			secFillRad.ConvertToNum(&_MergedVentInputValuse.secFilltRad);

		}
		else if (i == 3)
		{
			width.ConvertToNum(&_LateralVentInputValuse.width);
			depth.ConvertToNum(&_LateralVentInputValuse.depth);
			firstPadAng.ConvertToNum(&_LateralVentInputValuse.firstPaddingAng);
			secPadAng.ConvertToNum(&_LateralVentInputValuse.secPaddingAng);
			firstFillRad.ConvertToNum(&_LateralVentInputValuse.firstFilltRad);
			secFillRad.ConvertToNum(&_LateralVentInputValuse.secFilltRad);

		}

		if (pMultiList)
		{
			pMultiList->SetColumnItem(i, width, 0, CATDlgDataModify);
			pMultiList->SetColumnItem(i, depth, 1, CATDlgDataModify);
			pMultiList->SetColumnItem(i, firstPadAng, 2, CATDlgDataModify);
			pMultiList->SetColumnItem(i, secPadAng, 3, CATDlgDataModify);
			pMultiList->SetColumnItem(i, firstFillRad, 4, CATDlgDataModify);
			pMultiList->SetColumnItem(i, secFillRad, 5, CATDlgDataModify);
		}

	}
}

CATBoolean MRFCircumVentCmd::UpdateCircumVentDialog(CATBaseUnknown_var ispSpecObject)
{
	CATBoolean isUpdated = CATFalse;


	CATApplicationFrame * pAppFrame = CATApplicationFrame::GetFrame();
	if (NULL == pAppFrame)
		return isUpdated;

	CATDlgWindow * pMainWindow = pAppFrame->GetMainWindow();
	if (NULL == pMainWindow)
		return isUpdated;

	MRFICircumferentialVent_var spMRFCircumferentialVentFeat = ispSpecObject;

	CATListOfDouble defaultValueList, mergedValueList, lateralValueList;
	if (!!spMRFCircumferentialVentFeat)
	{
		spMRFCircumferentialVentFeat->GetBackProfile(_spBackProfileSurf);
		spMRFCircumferentialVentFeat->GetTyreAssemble(_spTyreSurface);
		spMRFCircumferentialVentFeat->GetDefaultGeomSet(_spDefaultCircumGeomSet);
		spMRFCircumferentialVentFeat->GetMergedGeomSet(_spMergedCircumGeomSet);
		spMRFCircumferentialVentFeat->GetLateralGeomSet(_spLateralCircumGHeomSet);
		spMRFCircumferentialVentFeat->GetDefaultValuesList(defaultValueList);
		spMRFCircumferentialVentFeat->GetMergedValuesList(mergedValueList);
		spMRFCircumferentialVentFeat->GetLateralValuesList(lateralValueList);


		this->GetMultiListValuesFromFeature(defaultValueList, mergedValueList, lateralValueList);
		this->ReadAndSetCircumVentValuesFromFeatToMultiList(defaultValueList, mergedValueList, lateralValueList);

		if (!!_spBackProfileSurf)
		{
			this->GetGeoFactory();
		}
		
		CATDlgSelectorList *pSelListOnBackProf = NULL,*pSelListOnTyreAssemble = NULL,*pSelListOnDefaultGeomSet = NULL,*pSelListOnMergedGeomSet = NULL,*pSelListOnLateralGeomSet = NULL;
		CATUnicodeString nameToSet;
		pSelListOnBackProf = _pMRFCircumVentDlg->GetBackProfileSelector();
		pSelListOnTyreAssemble = _pMRFCircumVentDlg->GetTyreAssySelector();
		pSelListOnDefaultGeomSet = _pMRFCircumVentDlg->GetDefaultRevolvesSelector();
		pSelListOnMergedGeomSet = _pMRFCircumVentDlg->GetMergedRevolvesSelector();
		pSelListOnLateralGeomSet = _pMRFCircumVentDlg->GetLateralRevolvesSelector();
		 
		if (pSelListOnBackProf)
		{
			if (!!_spBackProfileSurf)
			{
				CATPathElement* pPathElement = NULL;
				MRFGenericUtils::GetUIActivePathElement(_pEditor, _spBackProfileSurf, pPathElement);
				nameToSet = MRFGenericUtils::GetAliasName(_spBackProfileSurf);
				MRFGenericUtils::GetUIActivePathElement(_pEditor, _spBackProfileSurf, pPathElement);
				_pBackProfilePathElement = pPathElement;

			}
			else
			{
				nameToSet = "No Selection";
				_pMRFCircumVentDlg->SetSelectorListVentGeomSet(nameToSet, pSelListOnBackProf);

				CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
				if (NULL == pErrPanel)
					return isUpdated;

				// Set the text
				CATUnicodeString usWndTitle = "Warning Message", usMessage;

				usMessage.Append("BackProfile Surface is Not Selected\n");
				//usMessage.Append("The Product with Name: \"" + strOnNameOfPrdToInstantiate + "\" and Rev: \" " + strOnRev + "does not exists in database.\n");


				pErrPanel->DisplayBlocked(usMessage, usWndTitle);

				pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;

			}

			_pMRFCircumVentDlg->SetSelectorListVentGeomSet(nameToSet, pSelListOnBackProf);
		}
		if (pSelListOnTyreAssemble)
		{
			if (!!_spTyreSurface)
			{
				nameToSet = MRFGenericUtils::GetAliasName(_spTyreSurface);
				CATPathElement* pPathElement = NULL;
				MRFGenericUtils::GetUIActivePathElement(_pEditor, _spTyreSurface, pPathElement);
				_pTyreAssyPathElement = pPathElement;
			}
			else
			{
				nameToSet = "No Selection";
			}
		
			_pMRFCircumVentDlg->SetSelectorListVentGeomSet(nameToSet, pSelListOnTyreAssemble);
		}
		if (pSelListOnDefaultGeomSet)
		{
			if (!!_spDefaultCircumGeomSet)
			{
				nameToSet = MRFGenericUtils::GetAliasName(_spDefaultCircumGeomSet);

				CATPathElement* pPathElement = NULL;
				MRFGenericUtils::GetUIActivePathElement(_pEditor, _spDefaultCircumGeomSet, pPathElement);
				_pDefaultRevolvesPathElement = pPathElement;
			}
			else
			{
				nameToSet = "No Selection";
			}
			
			_pMRFCircumVentDlg->SetSelectorListVentGeomSet(nameToSet, pSelListOnDefaultGeomSet);
			ReadSelectedGeomSet("DefaultRevolves", _spDefaultCircumGeomSet);

		}
		if (pSelListOnMergedGeomSet)
		{
			if (!!_spMergedCircumGeomSet)
			{
				nameToSet = MRFGenericUtils::GetAliasName(_spMergedCircumGeomSet);
			CATPathElement* pPathElement = NULL;
			MRFGenericUtils::GetUIActivePathElement(_pEditor, _spMergedCircumGeomSet, pPathElement);

			_pMergedRevolvesPathElement = pPathElement;
			}
			else
			{
				nameToSet = "No Selection";
			}
			
			_pMRFCircumVentDlg->SetSelectorListVentGeomSet(nameToSet, pSelListOnMergedGeomSet);
			ReadSelectedGeomSet("MergedRevolves", _spMergedCircumGeomSet);
		}
		if (pSelListOnLateralGeomSet)
		{
			if (!!_spLateralCircumGHeomSet)
			{	nameToSet = MRFGenericUtils::GetAliasName(_spLateralCircumGHeomSet);
			CATPathElement* pPathElement = NULL;
			MRFGenericUtils::GetUIActivePathElement(_pEditor, _spLateralCircumGHeomSet, pPathElement);
			
			_pLateralRevolvesPathElement = pPathElement;

			if (_pHSO)
				_pHSO->AddElement(pPathElement);
			}
			else
			{
				nameToSet = "No Selection";
			}
			
			_pMRFCircumVentDlg->SetSelectorListVentGeomSet(nameToSet, pSelListOnLateralGeomSet);
			ReadSelectedGeomSet("LateralRevolves", _spLateralCircumGHeomSet);


			_pMRFCircumVentDlg->ClearOtherSelections("LateralRevolves");
			_pMRFCircumVentDlg->SetFocusOnSelectorList(pSelListOnLateralGeomSet);
		}


		isUpdated = CATTrue;
	}

	return isUpdated;
}

